namespace TicketClassifier.Models;

public class ModelMetrics
{
    public double MicroAccuracy { get; set; }
    public double MacroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public DateTime TrainedAt { get; set; }
    public int TrainingDataCount { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService
{
    private readonly MLContext _mlContext;
    private readonly ILogger<ModelTrainingService> _logger;
    private readonly string _modelPath;
    private readonly string _dataPath;

    public ModelMetrics? LastMetrics { get; private set; }

    public ModelTrainingService(ILogger<ModelTrainingService> logger, IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _logger = logger;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public string ModelPath => _modelPath;

    public void TrainAndSaveModel()
    {
        _logger.LogInformation("Loading training data from {Path}", _dataPath);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath,
            hasHeader: true,
            separatorChar: ',',
            allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Text
            .FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject))
            .Append(_mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(_mlContext.Transforms.Conversion.MapValueToKey("Label"))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on test set
        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        LastMetrics = new ModelMetrics
        {
            MicroAccuracy = metrics.MicroAccuracy,
            MacroAccuracy = metrics.MacroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction,
            TrainedAt = DateTime.UtcNow,
            TrainingDataCount = (int)_mlContext.Data.CreateEnumerable<TicketInput>(dataView, false).Count()
        };

        _logger.LogInformation(
            "Model trained — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}, LogLoss: {LogLoss:F4}",
            LastMetrics.MicroAccuracy, LastMetrics.MacroAccuracy, LastMetrics.LogLoss);

        // Also evaluate on full training data for comparison logging
        var fullPredictions = model.Transform(split.TrainSet);
        var trainMetrics = _mlContext.MulticlassClassification.Evaluate(fullPredictions);
        _logger.LogInformation(
            "Train set — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}",
            trainMetrics.MicroAccuracy, trainMetrics.MacroAccuracy);

        _mlContext.Model.Save(model, dataView.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;

    private static readonly string[] Categories = ["Billing", "Technical", "General"];

    public TicketsController(PredictionEnginePool<TicketInput, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("classify")]
    public ActionResult<TicketClassificationResult> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var result = new TicketClassificationResult
        {
            PredictedCategory = prediction.PredictedCategory,
            Confidence = Categories
                .Zip(prediction.Score, (cat, score) => new { cat, score })
                .ToDictionary(x => x.cat, x => x.score)
        };

        return Ok(result);
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class ModelController : ControllerBase
{
    private readonly ModelTrainingService _trainingService;

    public ModelController(ModelTrainingService trainingService)
    {
        _trainingService = trainingService;
    }

    [HttpGet("metrics")]
    public ActionResult<ModelMetrics> GetMetrics()
    {
        if (_trainingService.LastMetrics is null)
            return NotFound("Model has not been trained yet.");

        return Ok(_trainingService.LastMetrics);
    }

    [HttpPost("train")]
    public ActionResult<ModelMetrics> Train()
    {
        _trainingService.TrainAndSaveModel();
        return Ok(_trainingService.LastMetrics);
    }
}

