using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly string[] _labelNames;

    public TicketsController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        IWebHostEnvironment env)
    {
        _predictionPool = predictionPool;

        // Extract label names from the trained model's Score column metadata
        var mlContext = new MLContext();
        var modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
        var model = mlContext.Model.Load(modelPath, out _);

        var outputSchema = model.GetOutputSchema(SchemaDefinition.Create(typeof(TicketInput)));
        var scoreColumn = outputSchema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        _labelNames = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
    }

    [HttpPost("classify")]
    public ActionResult<TicketClassificationResult> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var result = new TicketClassificationResult
        {
            PredictedCategory = prediction.PredictedCategory,
            Confidence = _labelNames
                .Zip(prediction.Score, (label, score) => new { label, score })
                .ToDictionary(x => x.label, x => x.score)
        };

        return Ok(result);
    }
}

